/**
 * SIAKAD demo seeder.
 *
 * Adds realistic Indonesian-school dummy data on top of the baseline
 * (`seed.ts`): puluhan berita, 24 item galeri, 12 mata pelajaran, 6 kelas,
 * 120 siswa, 18 guru, 5 ujian CBT siap dijalankan, 30 hari absensi, 6 PPDB
 * applicants, pengumuman, jadwal pelajaran, nilai, dan parent links.
 *
 * Pictures are loaded from /public/img (AI-generated by scripts/generate-images.py).
 * If a hero/gallery image is missing, the seeder falls back to a placeholder URL
 * so the demo is still usable without pre-generated assets.
 *
 * Run AFTER `tsx prisma/seed.ts`:
 *   tsx prisma/seed-demo.ts
 */
import fs from 'node:fs';
import path from 'node:path';

import argon2 from 'argon2';

import { prisma } from '../src/shared/db/prisma';
import { ROLES, type RoleCode } from '../src/modules/rbac/permissions';

const PROJECT_ROOT = path.resolve(__dirname, '..');
const HERO_DIR = path.join(PROJECT_ROOT, 'public', 'img', 'hero');
const GAL_DIR = path.join(PROJECT_ROOT, 'public', 'img', 'gallery');
const NEWS_DIR = path.join(PROJECT_ROOT, 'public', 'img', 'news');

function publicImage(rel: string, fallback: string): string {
  const abs = path.join(PROJECT_ROOT, 'public', rel.replace(/^\//, ''));
  return fs.existsSync(abs) ? `/${rel.replace(/^\//, '')}` : fallback;
}

function pickHero(): string {
  for (const name of ['hero-1.jpg', 'hero-2.jpg', 'hero-3.jpg']) {
    const abs = path.join(HERO_DIR, name);
    if (fs.existsSync(abs)) return `/img/hero/${name}`;
  }
  return 'https://placehold.co/1280x720/1d4ed8/ffffff?text=SIAKAD';
}

function pickGalleryImage(i: number): string {
  const name = `gallery-${String(((i - 1) % 24) + 1).padStart(2, '0')}.jpg`;
  const abs = path.join(GAL_DIR, name);
  if (fs.existsSync(abs)) return `/img/gallery/${name}`;
  return `https://placehold.co/1280x720/1d4ed8/ffffff?text=Galeri+${i}`;
}

function pickNewsImage(i: number): string {
  const newsName = `news-${String(((i - 1) % 12) + 1).padStart(2, '0')}.jpg`;
  const newsAbs = path.join(NEWS_DIR, newsName);
  if (fs.existsSync(newsAbs)) return `/img/news/${newsName}`;
  // Fallback to gallery image if news image not generated yet.
  return pickGalleryImage(i);
}

