function pickName(seed: number): { fullName: string; gender: 'L' | 'P' } {
  const isMale = seed % 2 === 0;
  const first = isMale
    ? FIRST_NAMES_M[seed % FIRST_NAMES_M.length]!
    : FIRST_NAMES_F[seed % FIRST_NAMES_F.length]!;
  const last = LAST_NAMES[(seed * 7) % LAST_NAMES.length]!;
  return { fullName: `${first} ${last}`, gender: isMale ? 'L' : 'P' };
}

function slugify(s: string): string {
  return s
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/(^-|-$)+/g, '');
}

async function ensureRoles(): Promise<Record<RoleCode, string>> {
  const roles = await prisma.role.findMany({ where: { code: { in: Object.values(ROLES) } } });
  const map = {} as Record<RoleCode, string>;
  for (const r of roles) {
    map[r.code as RoleCode] = r.id;
  }
  return map;
}

