async function seedSubjects(): Promise<Map<string, string>> {
  const map = new Map<string, string>();
  for (const s of SUBJECTS) {
    const sub = await prisma.subject.upsert({
      where: { code: s.code },
      update: { name: s.name, kkm: s.kkm },
      create: s,
    });
    map.set(s.code, sub.id);
  }
  return map;
}

async function seedTeachers(roles: Record<RoleCode, string>): Promise<Array<{ id: string; fullName: string }>> {
  const teachers: Array<{ id: string; fullName: string }> = [];
  const password = await argon2.hash('Guru!2026', { type: argon2.argon2id });
  for (let i = 1; i <= 18; i++) {
    const { fullName } = pickName(i + 100);
    const username = `guru${String(i).padStart(2, '0')}`;
    const email = `${username}@sekolah-contoh.sch.id`;
    const nip = `1985${String(i).padStart(2, '0')}01200001`;
    const user = await prisma.user.upsert({
      where: { email },
      update: { isActive: true, fullName, nip },
      create: {
        email,
        username,
        passwordHash: password,
        fullName,
        nip,
        isActive: true,
        roles: { connect: [{ id: roles.guru! }] },
      },
    });
    teachers.push({ id: user.id, fullName });
  }
  // Designate first 6 as wali kelas as well
  const waliRole = roles.wali_kelas!;
  for (let i = 0; i < 6; i++) {
    await prisma.user.update({
      where: { id: teachers[i]!.id },
      data: { roles: { connect: [{ id: waliRole }] } },
    });
  }
  return teachers;
}

async function seedClasses(
  yearId: string,
  teachers: Array<{ id: string; fullName: string }>,
): Promise<Array<{ id: string; name: string; level: string }>> {
  const defs = [
    { name: 'X IPA-1', level: 'X' },
    { name: 'X IPS-1', level: 'X' },
    { name: 'XI IPA-1', level: 'XI' },
    { name: 'XI IPS-1', level: 'XI' },
    { name: 'XII IPA-1', level: 'XII' },
    { name: 'XII IPS-1', level: 'XII' },
  ];
  const out: Array<{ id: string; name: string; level: string }> = [];
  for (let i = 0; i < defs.length; i++) {
    const d = defs[i]!;
    const cls = await prisma.class.upsert({
      where: { academicYearId_name: { academicYearId: yearId, name: d.name } },
      update: { homeroomTeacherId: teachers[i]!.id, level: d.level },
      create: {
        academicYearId: yearId,
        name: d.name,
        level: d.level,
        homeroomTeacherId: teachers[i]!.id,
      },
    });
    out.push({ id: cls.id, name: cls.name, level: cls.level });
  }
  return out;
}

async function seedStudents(
  roles: Record<RoleCode, string>,
  classes: Array<{ id: string; name: string }>,
): Promise<Array<{ id: string; fullName: string; classId: string; classIndex: number }>> {
  const password = await argon2.hash('Siswa!2026', { type: argon2.argon2id });
  const out: Array<{ id: string; fullName: string; classId: string; classIndex: number }> = [];
  for (let i = 1; i <= 120; i++) {
    const classIndex = (i - 1) % classes.length;
    const cls = classes[classIndex]!;
    const { fullName } = pickName(i);
    const username = `siswa${String(i).padStart(3, '0')}`;
    const email = `${username}@siswa.sekolah-contoh.sch.id`;
    const nis = `2025${String(i).padStart(4, '0')}`;
    const user = await prisma.user.upsert({
      where: { email },
      update: { isActive: true, fullName, nis },
      create: {
        email,
        username,
        passwordHash: password,
        fullName,
        nis,
        isActive: true,
        roles: { connect: [{ id: roles.siswa! }] },
      },
    });
    await prisma.classEnrollment.upsert({
      where: { classId_studentId: { classId: cls.id, studentId: user.id } },
      update: {},
      create: { classId: cls.id, studentId: user.id },
    });
    out.push({ id: user.id, fullName, classId: cls.id, classIndex });
  }
  return out;
}

async function seedSchedules(
  classes: Array<{ id: string; name: string }>,
  subjects: Map<string, string>,
  teachers: Array<{ id: string }>,
): Promise<void> {
  const subjectCodes = [...subjects.keys()];
  const slots: Array<[number, string, string]> = [
    [1, '07:00', '08:30'],
    [1, '08:45', '10:15'],
    [1, '10:30', '12:00'],
    [2, '07:00', '08:30'],
    [2, '08:45', '10:15'],
    [3, '07:00', '08:30'],
    [3, '08:45', '10:15'],
    [4, '07:00', '08:30'],
    [5, '07:00', '08:30'],
  ];
  for (const cls of classes) {
    for (let s = 0; s < slots.length; s++) {
      const slot = slots[s]!;
      const subjId = subjects.get(subjectCodes[s % subjectCodes.length]!)!;
      const teacher = teachers[s % teachers.length]!;
      try {
        await prisma.classSchedule.upsert({
          where: {
            classId_dayOfWeek_startTime: {
              classId: cls.id,
              dayOfWeek: slot[0],
              startTime: slot[1],
            },
          },
          update: {},
          create: {
            classId: cls.id,
            subjectId: subjId,
            teacherId: teacher.id,
            dayOfWeek: slot[0],
            startTime: slot[1],
            endTime: slot[2],
            room: `R-${cls.name.replace(/\s+/g, '')}`,
          },
        });
      } catch {
        // Ignore unique-conflict racey upserts on dev DBs.
      }
    }
  }
}

async function seedAttendance(
  students: Array<{ id: string; fullName: string }>,
): Promise<void> {
  // 14 weekdays (avoid Sun=0 / Sat=6) up to today.
  const today = new Date();
  today.setHours(7, 0, 0, 0);
  const days: Date[] = [];
  for (let d = 0; d < 28 && days.length < 14; d++) {
    const date = new Date(today.getTime() - d * 24 * 60 * 60 * 1000);
    const dow = date.getDay();
    // Always include today (so the dashboard "hari ini" looks populated even on
    // weekends), then keep weekdays only for the rest of the history.
    if (d === 0 || (dow !== 0 && dow !== 6)) days.push(date);
  }
  const statuses = ['present', 'present', 'present', 'present', 'present', 'late', 'sick', 'permission', 'absent'];
  // Idempotent: clear existing demo attendance for these students within the
  // 14-day window so repeated `seed-demo` runs don't accumulate duplicates.
  const studentIds = students.map((s) => s.id);
  if (studentIds.length > 0 && days.length > 0) {
    const min = new Date(days[days.length - 1]!);
    min.setHours(0, 0, 0, 0);
    const max = new Date(days[0]!);
    max.setHours(23, 59, 59, 999);
    await prisma.attendanceMark.deleteMany({
      where: { studentId: { in: studentIds }, date: { gte: min, lte: max } },
    });
  }
  for (const stu of students) {
    for (const day of days) {
      // Deterministic pseudo-random by student+day.
      const seed = (stu.id.charCodeAt(0) + day.getDate()) % statuses.length;
      const status = statuses[seed]!;
      const notes =
        status === 'sick'
          ? 'Sakit demam'
          : status === 'permission'
            ? 'Izin keluarga'
            : status === 'late'
              ? 'Terlambat 10 menit'
              : status === 'absent'
                ? 'Tanpa keterangan'
                : null;
      try {
        await prisma.attendanceMark.create({
          data: {
            studentId: stu.id,
            date: day,
            status,
            notes: notes ?? undefined,
          },
        });
      } catch {
        // Skip if duplicate index (rare).
      }
    }
  }
}

async function seedExams(
  yearId: string,
  subjects: Map<string, string>,
  classes: Array<{ id: string; name: string }>,
): Promise<Array<{ id: string; title: string }>> {
  const defs = [
    { code: 'MTK', title: 'Penilaian Tengah Semester — Matematika' },
    { code: 'BIN', title: 'Penilaian Tengah Semester — Bahasa Indonesia' },
    { code: 'BIG', title: 'Penilaian Tengah Semester — Bahasa Inggris' },
    { code: 'FIS', title: 'Penilaian Akhir Semester — Fisika' },
    { code: 'INF', title: 'Penilaian Harian — Informatika' },
  ];
  const out: Array<{ id: string; title: string }> = [];
  const now = new Date();
  for (let i = 0; i < defs.length; i++) {
    const d = defs[i]!;
    const subjectId = subjects.get(d.code);
    if (!subjectId) continue;
    const startAt = new Date(now.getTime() - 30 * 60 * 1000);
    const endAt = new Date(now.getTime() + 24 * 60 * 60 * 1000);
    const exam = await prisma.exam.upsert({
      where: { id: `demo-exam-${i + 1}` },
      update: {
        title: d.title,
        startAt,
        endAt,
        durationMinutes: 60,
        isPublished: true,
      },
      create: {
        id: `demo-exam-${i + 1}`,
        academicYearId: yearId,
        subjectId,
        title: d.title,
        description:
          'Soal pilihan ganda, mode CBT dengan fullscreen lock, deteksi tab-switch, dan autosave jawaban.',
        startAt,
        endAt,
        durationMinutes: 60,
        shuffleQuestions: true,
        shuffleAnswers: true,
        isPublished: true,
        fullscreenRequired: true,
        preventTabSwitch: true,
        maxTabSwitches: 2,
      },
    });
    // Map ke semua kelas demo.
    for (const cls of classes) {
      await prisma.examClassMapping.upsert({
        where: { examId_classId: { examId: exam.id, classId: cls.id } },
        update: {},
        create: { examId: exam.id, classId: cls.id },
      });
    }
    // Soal contoh
    await seedQuestions(exam.id, d.code);
    out.push({ id: exam.id, title: exam.title });
  }
  return out;
}

