async function seedQuestions(examId: string, code: string): Promise<void> {
  const bank = QUESTION_BANK[code] ?? [];
  for (let i = 0; i < bank.length; i++) {
    const item = bank[i]!;
    // Pre-compute the deterministic question id we want (idempotent re-seeding).
    const qId = `${examId}-q${i + 1}`;
    const existing = await prisma.question.findUnique({ where: { id: qId } });
    if (existing) continue;
    await prisma.question.create({
      data: {
        id: qId,
        examId,
        type: 'mcq',
        prompt: item.q,
        order: i + 1,
        points: 1,
        choices: {
          create: item.choices.map((text, idx) => ({
            label: String.fromCharCode(65 + idx),
            text,
            isCorrect: idx === item.correctIndex,
            order: idx,
          })),
        },
      },
    });
  }
}

