async function seedNews(): Promise<void> {
  const now = Date.now();
  for (let i = 0; i < NEWS_TITLES.length; i++) {
    const item = NEWS_TITLES[i]!;
    const slug = `${slugify(item.title)}-${i + 1}`;
    const publishedAt = new Date(now - i * 36 * 60 * 60 * 1000); // every 1.5 days
    await prisma.newsPost.upsert({
      where: { slug },
      update: { isPublished: true, publishedAt, coverImageUrl: pickNewsImage(i + 1) },
      create: {
        slug,
        title: item.title,
        excerpt: item.excerpt,
        content: `<p>${item.excerpt}</p><p>Berita ini merupakan contoh konten dummy untuk SIAKAD. Konten lengkap akan ditulis oleh redaksi sekolah lewat panel CMS.</p><p>Liputan: tim humas SIAKAD. Foto: dokumentasi sekolah / AI generated.</p>`,
        coverImageUrl: pickNewsImage(i + 1),
        isPublished: true,
        publishedAt,
        seoTitle: item.title,
        seoDescription: item.excerpt,
      },
    });
  }
}

async function seedGallery(): Promise<void> {
  // Upsert categories.
  const catNames = Array.from(new Set(GALLERY_ITEMS.map((g) => g.category)));
  const cats = new Map<string, string>();
  for (let i = 0; i < catNames.length; i++) {
    const name = catNames[i]!;
    const slug = slugify(name);
    const cat = await prisma.galleryCategory.upsert({
      where: { slug },
      update: { name, order: i + 1 },
      create: { slug, name, order: i + 1 },
    });
    cats.set(name, cat.id);
  }
  for (let i = 0; i < GALLERY_ITEMS.length; i++) {
    const it = GALLERY_ITEMS[i]!;
    const id = `demo-gallery-${i + 1}`;
    const url = pickGalleryImage(i + 1);
    await prisma.galleryItem.upsert({
      where: { id },
      update: {
        title: it.title,
        imageUrl: url,
        thumbnailUrl: url,
        isPublished: true,
        categoryId: cats.get(it.category)!,
        order: i + 1,
      },
      create: {
        id,
        categoryId: cats.get(it.category)!,
        title: it.title,
        type: 'image',
        imageUrl: url,
        thumbnailUrl: url,
        order: i + 1,
        isPublished: true,
      },
    });
  }
}

